import React from 'react';
import { useMusic } from '../context/MusicContext'; // Chú ý: dùng 1 dấu chấm nếu cùng folder, 2 dấu nếu khác folder
import { Play, Pause, SkipBack, SkipForward, Heart, Volume2 } from 'lucide-react';

const GlobalPlayer = () => {
  const { 
    currentSong, isPlaying, togglePlay, handleNext, handlePrev, 
    favorites, toggleLike, currentTime, duration, seekTo 
  } = useMusic();

  if (!currentSong) return null;

  // Kiểm tra Like dựa trên ID
  const isLiked = favorites.includes(currentSong._id);

  // Hàm format thời gian (ví dụ: 125 giây -> 02:05)
  const formatTime = (time) => {
    if (!time) return "0:00";
    const min = Math.floor(time / 60);
    const sec = Math.floor(time % 60);
    return `${min}:${sec < 10 ? '0' : ''}${sec}`;
  };

  return (
    <div style={playerWrapper}>
      {/* Bên trái: Thông tin bài hát */}
      <div style={songSection}>
        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={albumArt} alt="" />
        <div style={textContainer}>
          <div style={songTitle}>{currentSong.title}</div>
          <div style={songArtist}>{currentSong.artist}</div>
        </div>
        <button onClick={() => toggleLike(currentSong._id)} style={btnIcon}>
          <Heart size={20} fill={isLiked ? "#1db954" : "none"} color={isLiked ? "#1db954" : "#b3b3b3"} />
        </button>
      </div>

      {/* Ở giữa: Bộ điều khiển & Thanh tiến trình */}
      <div style={controlsSection}>
        <div style={btnGroup}>
          <button onClick={handlePrev} style={btnSecondary}><SkipBack size={20}/></button>
          <button onClick={togglePlay} style={btnMain}>
            {isPlaying ? <Pause size={24} fill="#000"/> : <Play size={24} fill="#000" style={{marginLeft: '3px'}}/>}
          </button>
          <button onClick={handleNext} style={btnSecondary}><SkipForward size={20}/></button>
        </div>

        <div style={progressContainer}>
          <span style={timeLabel}>{formatTime(currentTime)}</span>
          <input 
            type="range"
            min="0"
            max={duration || 0}
            value={currentTime}
            onChange={(e) => seekTo(e.target.value)}
            style={sliderStyle}
          />
          <span style={timeLabel}>{formatTime(duration)}</span>
        </div>
      </div>

      {/* Bên phải: Âm lượng */}
      <div style={utilitySection}>
        <Volume2 size={20} color="#b3b3b3" />
        <input type="range" style={{width: '80px', accentColor: '#1db954'}} />
      </div>
    </div>
  );
};

/* --- STYLES --- */
const playerWrapper = { position: 'fixed', bottom: 0, left: 0, right: 0, height: '90px', background: '#181818', borderTop: '1px solid #282828', display: 'flex', alignItems: 'center', padding: '0 20px', zIndex: 2000, color: '#fff' };
const songSection = { display: 'flex', alignItems: 'center', width: '30%' };
const albumArt = { width: '56px', height: '56px', borderRadius: '4px', objectFit: 'cover' };
const textContainer = { marginLeft: '12px', marginRight: '12px' };
const songTitle = { fontSize: '14px', fontWeight: 'bold' };
const songArtist = { fontSize: '12px', color: '#b3b3b3' };
const controlsSection = { display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' };
const btnGroup = { display: 'flex', alignItems: 'center', gap: '20px', marginBottom: '5px' };
const btnMain = { background: '#fff', border: 'none', width: '35px', height: '35px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' };
const btnSecondary = { background: 'none', border: 'none', color: '#b3b3b3', cursor: 'pointer' };
const btnIcon = { background: 'none', border: 'none', cursor: 'pointer' };
const progressContainer = { display: 'flex', alignItems: 'center', gap: '10px', width: '100%' };
const timeLabel = { fontSize: '11px', color: '#b3b3b3', minWidth: '35px' };
const sliderStyle = { flex: 1, accentColor: '#1db954', cursor: 'pointer', height: '4px' };
const utilitySection = { display: 'flex', alignItems: 'center', justifyContent: 'flex-end', width: '30%' };

export default GlobalPlayer;
